41	  // declare shared memory structure
42	  // number of experts is bounded by number of threads
43	  __shared__ float __attribute((aligned(128))) smemScoreSigmoid[MaxNumExperts];
44	  __shared__ float __attribute((aligned(128))) smemScoreBias[MaxNumExperts];
45	  // number of expert groups is bounded by number of warps
46	  int constexpr NumWarps = MaxNumExperts / WARP_SIZE;
47	  __shared__ float __attribute((aligned(128))) smemGroupScores[NumWarps];
48	
49	  // needed for warp reduce
50	  auto block = cg::this_thread_block();
51	  auto warp = cg::tiled_partition<WARP_SIZE>(block);
52	
53	  // for the final reduction of weight norm, only some lanes need to participate
54	  int32_t laneIdx = threadIdx.x % WARP_SIZE;
55	  int32_t warpIdx = __shfl_sync(0xffffffff, threadIdx.x / WARP_SIZE, 0);
56	
57	  if constexpr (UseGroups) {
58	    if (warpIdx >= numGroup) {
59	      return;
60	    }
61	  }
62	
63	  // note that for invalid scores, we simply use a negative value:
64	  // they work well even with the compacted format used in topK, and
65	  // sigmoid / bias activated scores cannot be negative
66	  static constexpr float invalidScoreFloat = float{-INFINITY};
67	  const OutputT invalidScore = OutputT{invalidScoreFloat};
68	
69	  // load bias already; each warp represents one expert group
70	  auto threadExpert = threadIdx.x;
71	  bool expertSelected = threadExpert < numExperts;
72	  if constexpr (UseGroups) {
73	    threadExpert = warpIdx * numExpertsPerGroup + laneIdx;
74	    expertSelected = laneIdx < numExpertsPerGroup;
75	  }
76	
77	  auto scoreIdx = int64_t{blockIdx.x} * int64_t{numExperts} + threadExpert;
78	  auto biasVal = expertSelected ? static_cast<float>(routingBias[threadExpert]) : invalidScoreFloat;
79	  topkValues += blockIdx.x * topk;
80	  topkIndices += blockIdx.x * topk;
81	
82	  // get our assigned thread score; each warp represents one expert group
83	  float score = expertSelected ? static_cast<float>(scores[scoreIdx]) : invalidScoreFloat;
84	  auto scoreSigmoid = sigmoid_accurate(score);
85	  // write the sigmoid score to shared for later use
86	  if (expertSelected) {
87	    smemScoreSigmoid[threadExpert] = scoreSigmoid;
88	  }
89	
90	  // get the score with bias
91	  // note that with invalid values, because sigmoid is < 1 and bias is -1,
92	  // we must get a negative value, which is smaller than any valid value
93	  auto scoreBias = float{scoreSigmoid + float{biasVal}};
94	
95	  if (expertSelected) {
96	    smemScoreBias[threadExpert] = scoreBias;
97	  }
98	
99	  // registers for top group score reduction
100	  float topExpGroupScores[NumTopGroupScores];
101	  [[maybe_unused]] int32_t topExpGroupIdx[NumTopGroupScores];
102	  float topGroups[MaxNumTopGroups];  // bound of numGroup
103	  int32_t topGroupIdx[MaxNumTopGroups];
104	  float expertScoreGroup[MaxNumTopGroups];
105	  int32_t expertIdxGroup[MaxNumTopGroups];
106	  float topScores[MaxNumTopExperts];  // bound of topk
107	  int32_t topExperts[MaxNumTopExperts];
108	
109	  if constexpr (UseGroups) {
110	    reduce_topk::reduceTopK(warp, topExpGroupScores, topExpGroupIdx, scoreBias, threadExpert,
111	                            /* minValue */ invalidScoreFloat);
112	
113	    // get the final group score and write it to shared
114	    if (laneIdx == 0) {
115	      auto groupScore = topExpGroupScores[0] + topExpGroupScores[1];
116	      smemGroupScores[warpIdx] = groupScore;
117	    }
118	  }
119	
120	  // make group scores available to all warps
121	  __syncthreads();
122	
123	  if constexpr (UseGroups) {
124	    if (warpIdx == 0) {
125	      // a single warp performs the selection of top groups, and goes on to select the final experts
126	      float groupScore = laneIdx < numGroup ? smemGroupScores[laneIdx] : invalidScoreFloat;
127	
128	      reduce_topk::reduceTopK(warp, topGroups, topGroupIdx, groupScore, laneIdx,
129	                              /* minValue */ invalidScoreFloat);
130	
131	      // final expert selection: get relevant indexes and scores from shared
132	
133	#pragma unroll
134	      for (int ii = 0; ii < MaxNumTopGroups; ++ii) {  // bound of numGroup
135	        // auto groupIdx = topGroupIdx[ii];
136	        auto groupIdx = (ii < topkGroup) ? topGroupIdx[ii] : 0;
137	        expertIdxGroup[ii] = groupIdx * numExpertsPerGroup + laneIdx;
138	
139	        expertScoreGroup[ii] = (ii < topkGroup) && expertSelected
140	                                   ? smemScoreBias[expertIdxGroup[ii]]
141	                                   : invalidScoreFloat;
142	      }
143	
144	      tensorrt_llm::kernels::reduce_topk::reduceTopK(warp, topScores, topExperts, expertScoreGroup,
145	                                                     expertIdxGroup,
146	                                                     /* minValue */ invalidScoreFloat, topk);
147	    }
148	  } else if constexpr (MaxNumExperts > MaxNumExpertsUnit) {
149	    // without groups, and the expert number is larger than MaxNumExpertsUnit,
150	    // we need to use multiple warps to calculate the intermediate topk results
151	
152	    int constexpr NumExpertWarps = (MaxNumExperts - 1) / MaxNumExpertsUnit + 1;
153	    int constexpr NumInterTopK = NumExpertWarps * MaxNumTopExperts;
154	    __shared__ float __attribute((aligned(128))) smemInterTopScores[NumInterTopK];
155	    __shared__ int32_t __attribute((aligned(128))) smemInterTopExperts[NumInterTopK];
156	    if (warpIdx < NumExpertWarps) {
157	      int offset = warpIdx * WARP_SIZE * MaxNumTopGroups;
158	#pragma unroll
159	      for (int ii = 0; ii < MaxNumTopGroups; ++ii) {
160	        auto expertIdx = ii * WARP_SIZE + laneIdx;
161	        expertIdxGroup[ii] = offset + expertIdx;
162	        expertScoreGroup[ii] =
163	            offset + expertIdx < numExperts ? smemScoreBias[offset + expertIdx] : invalidScoreFloat;
164	      }
165	      reduce_topk::reduceTopK(warp, topScores, topExperts, expertScoreGroup, expertIdxGroup,
166	                              /* minValue */ invalidScoreFloat, topk);
167	
168	      if (laneIdx < topk) {
169	        smemInterTopScores[warpIdx * MaxNumTopExperts + laneIdx] = topScores[laneIdx];
170	        smemInterTopExperts[warpIdx * MaxNumTopExperts + laneIdx] = topExperts[laneIdx];
171	      }
172	    }
173	    __syncthreads();
174	    if (warpIdx == 0) {
175	      int constexpr NumInterTopKPerThread = (NumInterTopK * NumExpertWarps - 1) / WARP_SIZE + 1;
176	      float intermidiateScore[NumInterTopKPerThread];
177	      int32_t intermidiateExpert[NumInterTopKPerThread];
178	      for (int i = laneIdx; i < NumInterTopKPerThread * WARP_SIZE; i += WARP_SIZE) {
179	        int ii = i / WARP_SIZE;
180	        if (i < NumInterTopK) {
181	          intermidiateScore[ii] = smemInterTopScores[i];
182	          intermidiateExpert[ii] = smemInterTopExperts[i];
183	        } else {
184	          intermidiateScore[ii] = invalidScoreFloat;
185	          intermidiateExpert[ii] = MaxNumExperts - 1;
186	        }
187	      }
188	      reduce_topk::reduceTopK(warp, topScores, topExperts, intermidiateScore, intermidiateExpert,
189	                              /* minValue */ invalidScoreFloat, topk);
190	    }
191	  } else {
192	    // without groups, and the expert number is smaller than MaxNumExpertsUnit
193	    // each thread just takes `MaxNumTopGroups` experts
194	    if (warpIdx == 0) {
195	#pragma unroll
196	      for (int ii = 0; ii < MaxNumTopGroups; ++ii) {
197	        auto expertIdx = ii * WARP_SIZE + laneIdx;
198	        expertIdxGroup[ii] = expertIdx;
199	        expertScoreGroup[ii] =
200	            expertIdx < numExperts ? smemScoreBias[expertIdx] : invalidScoreFloat;
201	      }
202	      reduce_topk::reduceTopK(warp, topScores, topExperts, expertScoreGroup, expertIdxGroup,
203	                              /* minValue */ invalidScoreFloat, topk);
204	    }
205	  }
206	
207	  if (warpIdx == 0) {
208	    // determine our lane's expert index and write to output
209	    int32_t expertIdx = laneIdx < topk ? topExperts[laneIdx] : MaxNumExperts - 1;
210	    // norm the value
211	    float scoreNorm = laneIdx < topk ? smemScoreSigmoid[expertIdx] : 0.F;
212	    auto redNorm = cg::reduce(warp, scoreNorm, cg::plus<float>{});
213	    auto finalScore = static_cast<OutputT>(scoreNorm * routedScalingFactor / (redNorm + 1e-20));
214	    // store the topk scores and experts to output
215	    if (laneIdx < topk) {
216	      topkValues[laneIdx] = static_cast<OutputT>(finalScore);
217	      topkIndices[laneIdx] = expertIdx;
218	      // Routing replay: record selected expert IDs per token
219	      if (routingReplayOut != nullptr) {
220	        routingReplayOut[blockIdx.x * topk + laneIdx] = static_cast<int16_t>(expertIdx);
221	      }
222	    }
223	  }
224	
225	#if (defined(__CUDA_ARCH__) && (__CUDA_ARCH__ >= 900))
226	  asm volatile("griddepcontrol.launch_dependents;");
227	#endif
228	}
229	
230	template <typename InputT, typename BiasT, typename OutputT, typename IdxT>
231	void invokeNoAuxTc(InputT* scores, BiasT* bias, OutputT* topk_values, IdxT* topk_indices,
232	                   int64_t const num_tokens, int64_t const num_experts, int64_t const n_group,
233	                   int64_t const topk_group, int64_t const topk, double const routed_scaling_factor,
234	                   bool const launch_with_pdl, cudaStream_t const stream,
235	                   int16_t* routing_replay_out) {
236	  // Check if we can use the optimized deepseek_v3_topk_kernel
237	  bool const is_single_group = (n_group == 1) && (num_experts <= NumKimiK2Experts);
238	
239	  int64_t const experts_per_group = num_experts / n_group;
240	  bool const is_multi_group = (n_group != 1) && (num_experts <= NumDeepseekExperts) &&
241	                              (experts_per_group <= WARP_SIZE) &&
242	                              (experts_per_group * topk_group <= MaxNumExpertsUnit);
243	
244	  if (is_single_group || is_multi_group) {
245	    cudaLaunchConfig_t config;
246	    auto* kernel_instance =
247	        &deepseek_v3_topk_kernel<InputT, BiasT, OutputT, IdxT, NumDeepseekExperts, true>;
248	    int num_threads = NumDeepseekExperts;
249	    if (is_single_group) {
250	      if (num_experts > MaxNumExpertsUnit) {
251	        kernel_instance =
252	            &deepseek_v3_topk_kernel<InputT, BiasT, OutputT, IdxT, NumKimiK2Experts, false>;
253	        num_threads = NumKimiK2Experts;
254	      } else {
255	        kernel_instance =
256	            &deepseek_v3_topk_kernel<InputT, BiasT, OutputT, IdxT, MaxNumExpertsUnit, false>;
257	        num_threads = MaxNumExpertsUnit;
258	      }
259	    }
260	
261	    config.gridDim = num_tokens;
262	    config.blockDim = num_threads;
263	    config.dynamicSmemBytes = 0;
264	    config.stream = stream;
265	    cudaLaunchAttribute attrs[1];
266	    attrs[0].id = cudaLaunchAttributeProgrammaticStreamSerialization;
267	    attrs[0].val.programmaticStreamSerializationAllowed = launch_with_pdl;
268	    config.numAttrs = 1;
269	    config.attrs = attrs;
270	
271	    cudaLaunchKernelEx(&config, kernel_instance, scores, topk_values, topk_indices, bias,
272	                       num_tokens, n_group, topk_group, topk, num_experts, num_experts / n_group,
273	                       routed_scaling_factor, routing_replay_out);
274	    sync_check_cuda_error(stream);
275	  } else {
276	    // TODO: call the generic path (previous implementation) or signal unsupported config.
277	    TLLM_CHECK_WITH_INFO(false,
278	                         "invokeNoAuxTc: unsupported configuration (n_group=%ld, num_experts=%ld, "
279	                         "topk_group=%ld). Please use "
280	                         "original pytorch implementation.",
281	                         n_group, num_experts, topk_group);
282	  }
283	}
