285	#define INSTANTIATE_NOAUX_TC(InputT, BiasT, OutputT, IdxT)                              \
286	  template void invokeNoAuxTc<InputT, BiasT, OutputT, IdxT>(                            \
287	      InputT * scores, BiasT * bias, OutputT * topk_values, IdxT * topk_indices,        \
288	      int64_t const num_tokens, int64_t const num_experts, int64_t const n_group,       \
289	      int64_t const topk_group, int64_t const topk, double const routed_scaling_factor, \
290	      bool const launch_with_pdl, cudaStream_t const stream, int16_t* routing_replay_out);
291	
292	INSTANTIATE_NOAUX_TC(float, float, float, int32_t);
293	INSTANTIATE_NOAUX_TC(float, half, float, int32_t);
294	
295	INSTANTIATE_NOAUX_TC(half, float, half, int32_t);
296	INSTANTIATE_NOAUX_TC(half, half, half, int32_t);
297	
298	#ifdef ENABLE_BF16
299	INSTANTIATE_NOAUX_TC(float, __nv_bfloat16, float, int32_t);
300	INSTANTIATE_NOAUX_TC(half, __nv_bfloat16, half, int32_t);
301	
302	INSTANTIATE_NOAUX_TC(__nv_bfloat16, __nv_bfloat16, __nv_bfloat16, int32_t);
303	INSTANTIATE_NOAUX_TC(__nv_bfloat16, float, __nv_bfloat16, int32_t);
304	INSTANTIATE_NOAUX_TC(__nv_bfloat16, half, __nv_bfloat16, int32_t);
305	#endif
