307	}  // namespace tensorrt_llm::kernels
308	
309	namespace flashinfer::trtllm_dsv3_fused_routing {
310	// th::Tensor const& scores, th::Tensor const& bias, int64_t n_group,
311	// int64_t topk_group, int64_t topk, double routed_scaling_factor
312	// th::Tensor topk_values, th::Tensor topk_indices
313	
314	void NoAuxTc(TensorView scores, TensorView bias, int64_t n_group, int64_t topk_group, int64_t topk,
315	             double routed_scaling_factor, TensorView topk_values, TensorView topk_indices,
316	             bool launch_with_pdl, Optional<TensorView> routing_replay_out) {
317	  auto data_type = scores.dtype();
318	  auto bias_type = bias.dtype();
319	
320	  auto input_size = scores.sizes();
321	  int64_t num_tokens = input_size[0];
322	  int64_t num_experts = input_size[1];
323	
324	  TVM_FFI_ICHECK(input_size.size() == 2) << "scores must be a 2D Tensor";
325	  TVM_FFI_ICHECK((scores.device().device_type == kDLCUDA) && (bias.device().device_type == kDLCUDA))
326	      << "scores and bias must be CUDA tensors";
327	  TVM_FFI_ICHECK(scores.device().device_id == bias.device().device_id)
328	      << "scores and bias must be on the same device";
329	  TVM_FFI_ICHECK(bias.dim() == 1 && bias.numel() == num_experts)
330	      << "bias must be 1D with length == number of experts (%ld)";
331	  TVM_FFI_ICHECK(num_experts % n_group == 0) << "num_experts should be divisible by n_group";
332	  TVM_FFI_ICHECK(n_group <= 32)
333	      << "n_group should be smaller than or equal to 32 for now";  //@todo: remove this restriction
334	                                                                   // later
335	  TVM_FFI_ICHECK(topk <= 32)
336	      << "topk should be smaller than or equal to 32 for now";  //@todo: remove this restriction
337	                                                                // later
338	  TVM_FFI_ICHECK(topk_values.dim() == 2) << "topk_values must be a 2D Tensor";
339	  TVM_FFI_ICHECK(topk_indices.dim() == 2) << "topk_indices must be a 2D Tensor";
340	  TVM_FFI_ICHECK(topk_values.sizes()[0] == num_tokens)
341	      << "topk_values must have the same number of tokens as scores";
342	  TVM_FFI_ICHECK(topk_indices.sizes()[0] == num_tokens)
343	      << "topk_indices must have the same number of tokens as scores";
344	  TVM_FFI_ICHECK(topk_values.sizes()[1] == topk)
345	      << "topk_values must have the same number of topk as scores";
346	  TVM_FFI_ICHECK(topk_indices.sizes()[1] == topk)
347	      << "topk_indices must have the same number of topk as scores";
348	  TVM_FFI_ICHECK(topk_values.dtype() == data_type)
349	      << "topk_values must have the same dtype as scores";
350	  TVM_FFI_ICHECK(encode_dlpack_dtype(topk_indices.dtype()) == int32_code)
351	      << "topk_indices must be int32 dtype";
352	
353	  // Validate and extract routing_replay_out
354	  // NOTE: dim0 >= num_tokens is intentionally NOT checked — with CUDA graphs the buffer
355	  // is pre-allocated at maximum batch size and reused across steps with varying num_tokens.
356	  // The kernel only writes to indices [0, num_tokens), so a larger buffer is safe.
357	  constexpr int64_t int16_code_val = encode_dlpack_dtype(DLDataType{kDLInt, 16, 1});
358	  int16_t* replay_ptr = nullptr;
359	  if (routing_replay_out.has_value()) {
360	    auto replay = routing_replay_out.value();
361	    TVM_FFI_ICHECK(replay.device().device_type == kDLCUDA)
362	        << "routing_replay_out must be a CUDA tensor";
363	    TVM_FFI_ICHECK(replay.device().device_id == scores.device().device_id)
364	        << "routing_replay_out must be on the same device as scores";
365	    TVM_FFI_ICHECK(replay.ndim() == 2)
366	        << "routing_replay_out must be a 2D Tensor [num_tokens, topk]";
367	    TVM_FFI_ICHECK(replay.sizes()[1] == topk) << "routing_replay_out dim1 must equal topk";
368	    TVM_FFI_ICHECK(encode_dlpack_dtype(replay.dtype()) == int16_code_val)
369	        << "routing_replay_out must be int16 dtype";
370	    replay_ptr = reinterpret_cast<int16_t*>(replay.data_ptr());
371	  }
372	
373	  auto stream = get_stream(scores.device());
374	  using namespace tensorrt_llm::kernels;
375	  switch (encode_dlpack_dtype(data_type)) {
376	    case float16_code:
377	      // Handle Float16
378	      switch (encode_dlpack_dtype(bias_type)) {
379	        case float16_code:
380	          invokeNoAuxTc<half, half, half, int32_t>(
381	              reinterpret_cast<half*>(scores.data_ptr()), reinterpret_cast<half*>(bias.data_ptr()),
382	              reinterpret_cast<half*>(topk_values.data_ptr()),
383	              reinterpret_cast<int32_t*>(topk_indices.data_ptr()), num_tokens, num_experts, n_group,
384	              topk_group, topk, routed_scaling_factor, launch_with_pdl, stream, replay_ptr);
385	          break;
386	        case float32_code:
387	          invokeNoAuxTc<half, float, half, int32_t>(
388	              reinterpret_cast<half*>(scores.data_ptr()), reinterpret_cast<float*>(bias.data_ptr()),
389	              reinterpret_cast<half*>(topk_values.data_ptr()),
390	              reinterpret_cast<int32_t*>(topk_indices.data_ptr()), num_tokens, num_experts, n_group,
391	              topk_group, topk, routed_scaling_factor, launch_with_pdl, stream, replay_ptr);
392	          break;
393	        case bfloat16_code:
394	          invokeNoAuxTc<half, __nv_bfloat16, half, int32_t>(
395	              reinterpret_cast<half*>(scores.data_ptr()),
396	              reinterpret_cast<__nv_bfloat16*>(bias.data_ptr()),
397	              reinterpret_cast<half*>(topk_values.data_ptr()),
398	              reinterpret_cast<int32_t*>(topk_indices.data_ptr()), num_tokens, num_experts, n_group,
399	              topk_group, topk, routed_scaling_factor, launch_with_pdl, stream, replay_ptr);
400	          break;
401	        default:
402	          throw std::invalid_argument(
403	              "Invalid bias dtype, only supports float16, float32, and bfloat16");
404	          break;
405	      }
406	      break;
407	    case float32_code:
408	      switch (encode_dlpack_dtype(bias_type)) {
409	        case float32_code:
410	          invokeNoAuxTc<float, float, float, int32_t>(
411	              reinterpret_cast<float*>(scores.data_ptr()),
412	              reinterpret_cast<float*>(bias.data_ptr()),
413	              reinterpret_cast<float*>(topk_values.data_ptr()),
414	              reinterpret_cast<int32_t*>(topk_indices.data_ptr()), num_tokens, num_experts, n_group,
415	              topk_group, topk, routed_scaling_factor, launch_with_pdl, stream, replay_ptr);
416	          break;
417	        case float16_code:
418	          invokeNoAuxTc<float, half, float, int32_t>(
419	              reinterpret_cast<float*>(scores.data_ptr()), reinterpret_cast<half*>(bias.data_ptr()),
420	              reinterpret_cast<float*>(topk_values.data_ptr()),
421	              reinterpret_cast<int32_t*>(topk_indices.data_ptr()), num_tokens, num_experts, n_group,
422	              topk_group, topk, routed_scaling_factor, launch_with_pdl, stream, replay_ptr);
423	          break;
424	        case bfloat16_code:
425	          invokeNoAuxTc<float, __nv_bfloat16, float, int32_t>(
426	              reinterpret_cast<float*>(scores.data_ptr()),
427	              reinterpret_cast<__nv_bfloat16*>(bias.data_ptr()),
428	              reinterpret_cast<float*>(topk_values.data_ptr()),
429	              reinterpret_cast<int32_t*>(topk_indices.data_ptr()), num_tokens, num_experts, n_group,
430	              topk_group, topk, routed_scaling_factor, launch_with_pdl, stream, replay_ptr);
431	          break;
432	        default:
433	          throw std::invalid_argument(
434	              "Invalid bias dtype, only supports float16, float32, and bfloat16");
435	          break;
436	      }
437	      break;
438	    case bfloat16_code:
439	      // Handle BFloat16
440	      switch (encode_dlpack_dtype(bias_type)) {
441	        case bfloat16_code:
442	          invokeNoAuxTc<__nv_bfloat16, __nv_bfloat16, __nv_bfloat16, int32_t>(
443	              reinterpret_cast<__nv_bfloat16*>(scores.data_ptr()),
444	              reinterpret_cast<__nv_bfloat16*>(bias.data_ptr()),
445	              reinterpret_cast<__nv_bfloat16*>(topk_values.data_ptr()),
446	              reinterpret_cast<int32_t*>(topk_indices.data_ptr()), num_tokens, num_experts, n_group,
447	              topk_group, topk, routed_scaling_factor, launch_with_pdl, stream, replay_ptr);
448	          break;
449	        case float16_code:
450	          invokeNoAuxTc<__nv_bfloat16, half, __nv_bfloat16, int32_t>(
451	              reinterpret_cast<__nv_bfloat16*>(scores.data_ptr()),
452	              reinterpret_cast<half*>(bias.data_ptr()),
453	              reinterpret_cast<__nv_bfloat16*>(topk_values.data_ptr()),
454	              reinterpret_cast<int32_t*>(topk_indices.data_ptr()), num_tokens, num_experts, n_group,
455	              topk_group, topk, routed_scaling_factor, launch_with_pdl, stream, replay_ptr);
456	          break;
457	        case float32_code:
458	          invokeNoAuxTc<__nv_bfloat16, float, __nv_bfloat16, int32_t>(
459	              reinterpret_cast<__nv_bfloat16*>(scores.data_ptr()),
460	              reinterpret_cast<float*>(bias.data_ptr()),
461	              reinterpret_cast<__nv_bfloat16*>(topk_values.data_ptr()),
462	              reinterpret_cast<int32_t*>(topk_indices.data_ptr()), num_tokens, num_experts, n_group,
463	              topk_group, topk, routed_scaling_factor, launch_with_pdl, stream, replay_ptr);
464	          break;
465	        default:
466	          throw std::invalid_argument(
467	              "Invalid bias dtype, only supports bfloat16, float16, and float32");
468	          break;
469	      }
470	      break;
471	    default:
472	      // Handle other data types
473	      throw std::invalid_argument("Invalid dtype, only supports float16, float32, and bfloat16");
474	      break;
475	  }
476	}
477	TVM_FFI_DLL_EXPORT_TYPED_FUNC(NoAuxTc, flashinfer::trtllm_dsv3_fused_routing::NoAuxTc);
478	}  // namespace flashinfer::trtllm_dsv3_fused_routing
