35	// Implementation of shared post-topK pipeline for all routing methods.
36	// When topK is already computed (mPtrTopKIds or mPtrTopKPacked), we don't need
37	// routing-method-specific logic, so all methods can use the same workflow.
38	// This function handles all path selection: single-block, single-cluster, coop, multi-kernel.
39	template <typename DataType>
40	void runPostTopKPipeline(DataType const& data, void* stream) {
41	  // Convert to routingCustom::Data for launching (kernels are shared)
42	  routingCustom::Data customData;
43	  // Copy base fields
44	  static_cast<DataBase&>(customData) = static_cast<DataBase const&>(data);
45	  // Set routingCustom-specific defaults (not needed for utility kernels)
46	  customData.mDtypeOutput = data.mDtypeOutput;
47	  // The post-TopK kernels don't read routing logits (mPtrInput), only mPtrTopKPacked.
48	  // Set mDtypeInput = mDtypeOutput so the dispatched template is <OutputT, OutputT>,
49	  // avoiding an unnecessary mixed-type instantiation.
50	  customData.mDtypeInput = data.mDtypeOutput;
51	  // Softmax is chosen for its broad tier coverage, not because we need softmax.
52	  // The TopKIds/TopKPacked branches never call ExpertSelectPolicy::apply(),
53	  // so the postprocess is never executed.  Using Softmax avoids extra template
54	  // instantiations by reusing tiers already compiled for other models.
55	  customData.mPreprocessType = RoutingPreprocessType::None;
56	  customData.mPostprocessType = RoutingPostprocessType::Softmax;
57	
58	  // Recompute numThreadsHist using routingCustom's expert tiers, since we launch custom kernels.
59	  // Different routing methods (DeepSeek, Llama4) may have different expert tier thresholds
60	  // that don't match routingCustom's tiers (128, 512, 2048).
61	  uint32_t const numThreadsHist =
62	      std::min(1024u, static_cast<uint32_t>(routingCustom::getMaxNumExperts(data.mNumExperts)));
63	
64	  // Determine which path to use based on token count
65	  static int const smMajor = tensorrt_llm::common::getSMVersion() / 10;
66	  bool const useStaticBlock = data.mNumTokens <= routingCustom::BlockKernelMaxNumTokens;
67	  // Use the dispatched tier size (not raw mNumExperts).
68	  // Example: 512 experts with topK=22 skips Tier<512,8> and lands on
69	  // Tier<1024,32>, so queryDispatchedMaxExperts() returns 1024 while
70	  // mNumExperts is 512.  The dynblock kernel sizes smem proportional to
71	  // maxExperts; using the raw count would exceed the smem budget.
72	  // Use customData (routingCustom::Data) since queryDispatchedMaxExperts
73	  // requires routingCustom::Data, not the template DataType.
74	  int32_t const dispatchedMaxExperts = routingCustom::queryDispatchedMaxExperts(customData);
75	  bool const useDynBlock = !useStaticBlock &&
76	                           data.mNumTokens <= routingCustom::DynBlockKernelMaxNumTokens &&
77	                           dispatchedMaxExperts <= routingCustom::DynBlockKernelMaxNumExperts;
78	  // runPostTopKPipeline only handles pre-computed topK (mPtrTopKIds or mPtrTopKPacked),
79	  // never raw scores. The cluster kernel's routingPermutation uses thread-per-expanded-index
80	  // for both input types (LoadExpertIdxFromGlobal=true), so the capacity is
81	  // NumBlocksPerCluster * NumThreads = 8192 tokens.
82	  bool const useSingleCluster =
83	      (smMajor >= 9) && (data.mNumTokens <= routingCustom::MaxNumTokensSingleCluster);
84	
85	  if (useDynBlock) {
86	    routingCustom::launchDynBlockKernel(customData, numThreadsHist, stream);
87	  } else if (useStaticBlock) {
88	    routingCustom::launchBlockKernel(customData, numThreadsHist, stream);
89	  } else if (useSingleCluster) {
90	    routingCustom::launchClusterKernel(customData, stream);
91	  } else {
92	    // Check if we can use the coop path (more efficient for medium token counts)
93	    // Requires SM90+ (grid-sync), numExperts <= 1024.
94	    // Note: NumTop8Experts is used for template instantiation but does NOT limit runtime topK —
95	    // the coop kernel uses hardcoded MaxExpandedIdxPerThread=64 and runtime params.mTopK.
96	    bool const canUseCoop = (smMajor >= 9) && (data.mNumExperts <= 1024) &&
97	                            (data.mPtrPermutedIdxSize != nullptr) &&
98	                            (data.mPtrExpertCounts != nullptr);
99	    bool useCoop = false;
100	    CoopLaunchSMCounts coopLaunchSMCounts{0, 0};
101	    int numBlocksCoop = 0;
102	
103	    if (canUseCoop) {
104	      // Number of blocks we can use in the cooperative kernel
105	      static int const smCount = tensorrt_llm::common::getMultiProcessorCount();
106	      coopLaunchSMCounts = getCoopLaunchSMCounts(smCount);
107	      numBlocksCoop = coopLaunchSMCounts.moeSms;
108	      // Maximum number of tokens supported by the kernel using a cooperative launch.
109	      // The number of blocks must be:
110	      //   >= ⌈(numTokens * topK) / (MaxExpandedIdxPerThread * NumThreads)⌉
111	      // MaxExpandedIdxPerThread = 64 (from coop kernel)
112	      int const maxTokensCoop = (numBlocksCoop * numThreadsHist * 64) / data.mTopK;
